import { useLocation, useNavigate } from "react-router-dom";
import { useState } from "react";

function AddBook() {
  const location = useLocation();
  const navigate = useNavigate();

  const genre = location.state?.genre;

  const [title, setTitle] = useState("");
  const [author, setAuthor] = useState("");
  const [cover, setCover] = useState("");
  const [message, setMessage] = useState("");

  const handleAddBook = () => {
    if (!title || !author || !cover) {
      setMessage("⚠️ All fields are required");
      return;
    }

    // 1️⃣ get existing books from localStorage
    const storedBooks =
      JSON.parse(localStorage.getItem("genreBooks")) || {};

    // 2️⃣ ensure genre array exists
    if (!storedBooks[genre]) {
      storedBooks[genre] = [];
    }

    // 3️⃣ add new book
    storedBooks[genre].push({
      title,
      author,
      cover,
      status: "Available",
    });

    // 4️⃣ save back
    localStorage.setItem("genreBooks", JSON.stringify(storedBooks));

    // 5️⃣ feedback
    setMessage("✅ Book added successfully!");

    // optional reset
    setTitle("");
    setAuthor("");
    setCover("");
  };

  return (
    <div className="books-page">
      <h1 className="books-title">Add New {genre} Book</h1>

      <div className="detail-card">
        <input
          placeholder="Book Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <input
          placeholder="Author"
          value={author}
          onChange={(e) => setAuthor(e.target.value)}
        />

        <input
          placeholder="Cover Image URL"
          value={cover}
          onChange={(e) => setCover(e.target.value)}
        />

        <button className="borrow-btn" onClick={handleAddBook}>
          Add Book
        </button>

        {message && <p style={{ marginTop: "12px" }}>{message}</p>}

        <button
          className="back-btn"
          onClick={() => navigate(-1)}
          style={{ marginTop: "20px" }}
        >
          ← Back
        </button>
      </div>
    </div>
  );
}

export default AddBook;
